// NODE: Parse Video Pipeline Message
// Routes incoming Telegram messages to the correct handler:
//   - #body scenario_name clip_index [section]  → body clip upload
//   - #hook scenario_name                       → manual hook clip upload
//   - #outro scenario_name label                → manual outro clip upload
//   - /produce scenario_name [template]         → trigger video production
//   - /done                                     → finish recording (does NOT auto-start next)
//   - /next                                     → manually start recording next approved scenario
//   - video with no caption (during recording)  → auto body clip
//   - anything else                             → ignored
// Mode: Run Once for All Items
//
// WIRING: Telegram Trigger (message) → this Code node → Switch node (Route Message)
// Switch outputs: body_clip | hook_clip | outro_clip | produce | done_recording | start_next | auto_body_clip | unknown

const update = $input.first().json;
const message = update.message || update;
const text = (message.caption || message.text || '').trim();
const chatId = message.chat?.id || '';

const hasVideo = !!(message.video || message.document);
const video = message.video || message.document || {};

// ─── Static data (needed for /produce timeOfDay fallback + auto_body_clip) ───
const staticData = $getWorkflowStaticData('global');

// ─── #body scenario_name clip_index [section] ───
const bodyMatch = text.match(/#body\s+(\S+)\s+(\d+)(?:\s+(\S+))?/i);
if (hasVideo && bodyMatch) {
  return [{
    json: {
      messageType: 'body_clip',
      scenarioName: bodyMatch[1],
      clipIndex: parseInt(bodyMatch[2], 10),
      section: bodyMatch[3] || '',
      fileId: video.file_id,
      fileSize: video.file_size || 0,
      duration: video.duration || 0,
      chatId,
    }
  }];
}

// ─── #hook scenario_name ───
const hookMatch = text.match(/#hook\s+(\S+)/i);
if (hasVideo && hookMatch) {
  return [{
    json: {
      messageType: 'hook_clip',
      scenarioName: hookMatch[1],
      fileId: video.file_id,
      fileSize: video.file_size || 0,
      duration: video.duration || 0,
      chatId,
    }
  }];
}

// ─── #outro scenario_name label ───
const outroMatch = text.match(/#outro\s+(\S+)\s+(\S+)/i);
if (hasVideo && outroMatch) {
  return [{
    json: {
      messageType: 'outro_clip',
      scenarioName: outroMatch[1],
      label: outroMatch[2],
      fileId: video.file_id,
      fileSize: video.file_size || 0,
      duration: video.duration || 0,
      chatId,
    }
  }];
}

// ─── /produce [scenario_name] [night|day] — no args = next ready scenario ───
// Examples: /produce  |  /produce my-scenario  |  /produce my-scenario night  |  /produce night
if (text.match(/^\/produce/i)) {
  const parts = text.trim().split(/\s+/);
  let scenarioName = '';
  let explicitTimeOfDay = null;
  for (let i = 1; i < parts.length; i++) {
    if (parts[i].match(/^(night|day)$/i)) {
      explicitTimeOfDay = parts[i].toLowerCase();
    } else if (parts[i]) {
      scenarioName = parts[i];
    }
  }
  // Fall back to time recorded during /done → /night|/day (stored in static data)
  const timeOfDay = explicitTimeOfDay || staticData.activeRecordingTimeOfDay || 'day';
  return [{ json: { messageType: 'produce', scenarioName, timeOfDay, chatId } }];
}

// ─── /day or /night — set lighting time after /done ───
if (text.match(/^\/(day|night)$/i)) {
  const timeOfDay = text.match(/^\/night$/i) ? 'night' : 'day';
  return [{
    json: {
      messageType: 'set_time_of_day',
      timeOfDay,
      chatId,
    }
  }];
}

// ─── /done — finish recording ───
if (text.match(/^\/done$/i)) {
  const activeRec = staticData.activeRecording;
  return [{
    json: {
      messageType: 'done_recording',
      scenarioName: activeRec ? activeRec.scenarioName : '',
      chatId,
    }
  }];
}

// ─── /next — manually start recording next approved scenario ───
if (text.match(/^\/next$/i)) {
  return [{
    json: {
      messageType: 'start_next',
      chatId,
    }
  }];
}

// ─── Video with no recognized command during active recording → auto body clip ───
if (hasVideo && staticData.activeRecording) {
  return [{
    json: {
      messageType: 'auto_body_clip',
      fileId: video.file_id,
      fileSize: video.file_size || 0,
      duration: video.duration || 0,
      chatId,
    }
  }];
}

// Unknown — ignore silently
return [{
  json: {
    messageType: 'unknown',
    text: text.substring(0, 100),
    chatId,
  }
}];

// NODE: Save Clip (unified handler for body/hook/outro)
// Prepares the Airtable record for any clip type uploaded via Telegram
// Mode: Run Once for All Items
//
// WIRING: Parse Message → Route Message (Switch) → Find Scenario → this Code node → Airtable Create → Telegram confirm
//
// Input: parsed message data from Parse Message + scenario record from Find Scenario
// Handles all 3 clip types: body_clip, hook_clip, outro_clip

const parsed = $('Parse Message').first().json;
const scenario = $('Find Scenario (Clip)').first().json;

if (!scenario || !scenario.id) {
  return [{
    json: {
      error: true,
      chatId: parsed.chatId,
      message: 'Scenario "' + parsed.scenarioName + '" not found in Airtable'
    }
  }];
}

const messageType = parsed.messageType;

// Build the Airtable record fields based on clip type
const record = {
  scenario_id: [scenario.id],
  telegram_file_id: parsed.fileId,
  clip_duration_sec: parsed.duration,
  status: 'uploaded',
};

if (messageType === 'body_clip') {
  record.clip_name = parsed.scenarioName + '_body_' + parsed.clipIndex;
  record.clip_type = 'body';
  record.clip_index = parsed.clipIndex;
  record.section = parsed.section || '';  // optional template section mapping
} else if (messageType === 'hook_clip') {
  record.clip_name = parsed.scenarioName + '_hook';
  record.clip_type = 'hook_manual';
  record.clip_index = 0;
} else if (messageType === 'outro_clip') {
  record.clip_name = parsed.scenarioName + '_outro_' + parsed.label;
  record.clip_type = 'outro_manual';
  record.clip_index = 0;
  record.label = parsed.label || '';
}

// Build confirmation message
let confirmMsg = '';
if (messageType === 'body_clip') {
  confirmMsg = '\u2705 Body clip #' + parsed.clipIndex + ' saved for "' + parsed.scenarioName + '"';
  if (parsed.section) confirmMsg += ' (section: ' + parsed.section + ')';
} else if (messageType === 'hook_clip') {
  confirmMsg = '\u2705 Hook clip saved for "' + parsed.scenarioName + '"';
} else if (messageType === 'outro_clip') {
  confirmMsg = '\u2705 Outro clip "' + parsed.label + '" saved for "' + parsed.scenarioName + '"';
}

return [{
  json: {
    ...record,
    chatId: parsed.chatId,
    scenarioName: parsed.scenarioName,
    confirmMsg,
  }
}];

// NODE: Prepare Production (Dynamic — reads concept, template, music from Airtable)
// Consolidates all loaded data into a production plan
// Mode: Run Once for All Items
//
// WIRING: Find Music → this Code node → Produce Error? → Create Video Run → Generate Hook
// References: $('Parse Message'), $('Find Scenario (Produce)'), $('Find Concept'),
//             $('Find Body Clips'), $('Find Template'), $('Find Music')

// Helper: "toxic-sad-happy-girl-1771197483216" → "Toxic Sad Happy Girl"
function formatName(raw) {
  if (!raw) return 'Scenario';
  return raw.replace(/-\d{10,}$/, '').split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
}

const chatId = $('Parse Message').first().json.chatId;
const timeOfDay = $('Parse Message').first().json.timeOfDay || 'day'; // 'night' | 'day'

// ——— Scenario ———
const scenarioItems = $('Find Scenario (Produce)').all().map(i => i.json);
if (scenarioItems.length === 0 || !scenarioItems[0].id) {
  return [{
    json: {
      error: true,
      chatId,
      message: '\u26A0\uFE0F Nessuno scenario pronto (status=ready) trovato.',
    }
  }];
}

const scenario = scenarioItems[0];
const scenarioName = scenario.scenario_name;

let scenarioJson = scenario.scenario_json;
if (typeof scenarioJson === 'string') {
  try { scenarioJson = JSON.parse(scenarioJson); } catch(e) { scenarioJson = null; }
}

let copyJson = scenario.generated_copy_json;
if (typeof copyJson === 'string') {
  try { copyJson = JSON.parse(copyJson); } catch(e) { copyJson = null; }
}

// ——— Concept config ———
const conceptItems = $('Find Concept').all().map(i => i.json);
const concept = conceptItems.length > 0 && conceptItems[0].id ? conceptItems[0] : {};
const hookType = concept.hook_type || 'chat_screenshot';
const girlRefUrl = concept.girl_ref_url || '';
const hookPromptTemplate = concept.hook_prompt_template || '';
const outroPromptTemplate = concept.outro_prompt_template || '';
const hookEmotionRule = concept.hook_emotion_rule || 'match_toxicity';
const girlStylePrompt = concept.girl_style_prompt || '';
const environmentDescription = concept.environment_description || '';
const environmentFurniture = concept.environment_furniture || '';
const hookImageSystemPrompt = concept.hook_image_system_prompt || '';
const outroImageSystemPrompt = concept.outro_image_system_prompt || '';

// Outro pool: parse JSON, weighted random selection
let selectedOutro = { type: 'none' };
let outroPoolRaw = concept.outro_pool_json;
if (typeof outroPoolRaw === 'string') {
  try { outroPoolRaw = JSON.parse(outroPoolRaw); } catch(e) { outroPoolRaw = null; }
}
if (Array.isArray(outroPoolRaw) && outroPoolRaw.length > 0) {
  const enabled = outroPoolRaw.filter(o => o.enabled !== false);
  if (enabled.length > 0) {
    const totalWeight = enabled.reduce((s, o) => s + (o.weight || 1), 0);
    let rand = Math.random() * totalWeight;
    for (const opt of enabled) {
      rand -= (opt.weight || 1);
      if (rand <= 0) { selectedOutro = opt; break; }
    }
    if (selectedOutro.type === undefined) selectedOutro = enabled[0];
  }
}

// ——— Sub-concept selection (for concepts with variants like sad-happy-girl) ———
let selectedSubconcept = null;
let effectiveHookType = hookType;
let effectiveOutroType = selectedOutro.type;
let hookRefImageUrl = girlRefUrl;
let outroRefImageUrl = girlRefUrl;
let hookKlingPrompt = '';
let outroKlingPrompt = '';
let hookKlingDuration = null;

let subconceptsRaw = concept.sub_concepts_json;
if (typeof subconceptsRaw === 'string') {
  try { subconceptsRaw = JSON.parse(subconceptsRaw); } catch(e) { subconceptsRaw = null; }
}

if (Array.isArray(subconceptsRaw) && subconceptsRaw.length > 0) {
  const enabledSc = subconceptsRaw.filter(sc => sc.enabled !== false);
  if (enabledSc.length > 0) {
    // Weighted random selection (same algo as outro pool)
    const totalScWeight = enabledSc.reduce((s, sc) => s + (sc.weight || 1), 0);
    let scRand = Math.random() * totalScWeight;
    for (const sc of enabledSc) {
      scRand -= (sc.weight || 1);
      if (scRand <= 0) { selectedSubconcept = sc; break; }
    }
    if (!selectedSubconcept) selectedSubconcept = enabledSc[0];

    // Override hook/outro types from sub-concept
    effectiveHookType = selectedSubconcept.hook_type || hookType;
    effectiveOutroType = selectedSubconcept.outro_type || selectedOutro.type;
    hookKlingPrompt = selectedSubconcept.hook_prompt || '';
    outroKlingPrompt = selectedSubconcept.outro_prompt || '';

    // Randomize motion prompts for reaction (candid, not selfie) — V2.0
    if (selectedSubconcept.hook_type === 'reaction' && !hookKlingPrompt) {
      // STRATEGY: phone is always HELD STILL — she is REACTING, not actively operating it.
      // V2.0: two separate pools (cold_calculated vs explosive_control) + eye focus randomization.

      // Determine poseCategory from toxicity score (mirrors generate-hook.js logic)
      let poseCategory = 'cold_calculated';
      if (hookEmotionRule !== 'always_sad' && hookEmotionRule !== 'always_shocked') {
        const sc = scenarioJson ? (scenarioJson.overallScore || scenarioJson.toxicityScore || 15) : 15;
        poseCategory = sc <= 15 ? 'cold_calculated' : 'explosive_control';
      }

      // Weighted eye focus randomizer — micro saccade language (humans do this, AI doesn't)
      const eyeFocusOpts = [
        { weight: 40, text: 'eyes naturally settling forward, brief micro saccade before focusing' },
        { weight: 30, text: 'eyes slightly past camera, micro saccade then settle' },
        { weight: 20, text: 'eyes briefly downward then naturally shift forward' },
        { weight: 10, text: 'eyes naturally drift to side then refocus forward' },
      ];
      function pickEyeFocus() {
        const total = eyeFocusOpts.reduce((s, o) => s + o.weight, 0);
        let r = Math.random() * total;
        for (const opt of eyeFocusOpts) { r -= opt.weight; if (r <= 0) return opt.text; }
        return eyeFocusOpts[0].text;
      }

      // Cold pool — glacial, minimal, physical micro-action (85–99% toxic tier)
      const coldMotionPool = [
        'Locked off tripod shot, static camera — she is sitting holding her phone still, not typing, remains completely still for a moment, blinks once slowly, jaw subtly tightens, {EYE}, no tears, dry eyes',
        'Locked off tripod shot, static camera — she is sitting holding her phone still, not typing, barely tilts chin forward, breath steady and controlled, minimal movement, {EYE}, no tears, dry eyes',
        'Locked off tripod shot, static camera — she is sitting holding her phone still, not typing, micro eyebrow lift, no other visible movement, {EYE}, no tears, dry eyes',
        'Locked off tripod shot, static camera — she is sitting holding her phone still, not typing, holds completely still, slow controlled exhale through nose, {EYE}, no tears, dry eyes',
        'Locked off tripod shot, static camera — she is sitting holding her phone still, not typing, slight head tilt, expression unreadable, stillness dominates, {EYE}, no tears, dry eyes',
      ];

      // Explosive pool — contained physical tension (70–84% toxic tier)
      const explosiveMotionPool = [
        'Locked off tripod shot, static camera — she is sitting holding her phone still, not typing, sharp short exhale, jaw tightens briefly, {EYE}, no tears, dry eyes',
        'Locked off tripod shot, static camera — she is sitting holding her phone still, not typing, quick blink of disbelief, minimal head shift, {EYE}, no tears, dry eyes',
        'Locked off tripod shot, static camera — she is sitting holding her phone still, not typing, subtle head shake once, lips press then relax, {EYE}, no tears, dry eyes',
        'Locked off tripod shot, static camera — she is sitting holding her phone still, not typing, eyes widen slightly before narrowing, {EYE}, no tears, dry eyes',
        'Locked off tripod shot, static camera — she is sitting holding her phone still, not typing, visible tension in jaw and neck, small breath reset, {EYE}, no tears, dry eyes',
      ];

      // 15% energy contrast injection — deliberately mismatches tier for human feel
      const useContrast = Math.random() < 0.15;
      const motionPool = (poseCategory === 'cold_calculated' && !useContrast) ? coldMotionPool : explosiveMotionPool;

      // Pick prompt and inject randomized eye focus
      const rawPrompt = motionPool[Math.floor(Math.random() * motionPool.length)];
      hookKlingPrompt = rawPrompt.replace('{EYE}', pickEyeFocus());

    }
    hookKlingDuration = selectedSubconcept.hook_duration || null;

    // Seedance v1.5 Pro only supports '5' and '10' — leave null to use SEEDANCE_DURATION default

    // Image prompts for kie.ai (generate original images each time)
    // These override the AI-generated prompt or fallback template in generate-hook/outro
    // hook_ref_field / outro_ref_field are optional for pre-made refs (not used with kie.ai generation)
    if (selectedSubconcept.hook_ref_field && concept[selectedSubconcept.hook_ref_field]) {
      let urls = concept[selectedSubconcept.hook_ref_field];
      if (typeof urls === 'string') { try { urls = JSON.parse(urls); } catch(e) { urls = [urls]; } }
      if (Array.isArray(urls) && urls.length > 0) hookRefImageUrl = urls[Math.floor(Math.random() * urls.length)];
    }
    if (selectedSubconcept.outro_ref_field && concept[selectedSubconcept.outro_ref_field]) {
      let urls = concept[selectedSubconcept.outro_ref_field];
      if (typeof urls === 'string') { try { urls = JSON.parse(urls); } catch(e) { urls = [urls]; } }
      if (Array.isArray(urls) && urls.length > 0) outroRefImageUrl = urls[Math.floor(Math.random() * urls.length)];
    }
  }
}

// ——— Outro Category Override (from Workflow 1 copyJson) ———
// outroCategory is set during scenario generation: 'organic', 'app_store', 'cta_lipsync'
const outroCategory = (copyJson && copyJson.outroCategory) || 'organic';

if (outroCategory === 'app_store') {
  // App store clip — override whatever the outro pool selected
  selectedOutro = { type: 'app_store_clip', label: 'app_store', weight: 0 };
  effectiveOutroType = 'app_store_clip';
} else if (outroCategory === 'cta_lipsync') {
  // Sora 2 speaking video — override outro type
  effectiveOutroType = 'speaking';
}
// 'organic' → keep existing outro_pool_json selection (no override)

// ——— Body clips (from Find Body Clips, includes all clip types) ———
const clipRecords = $('Find Body Clips').all().map(i => i.json);
if (clipRecords.length === 0 || !clipRecords[0].id) {
  return [{
    json: {
      error: true,
      chatId,
      message: '\u26A0\uFE0F Nessuna body clip trovata per "' + formatName(scenarioName) + '". Registra prima le clip.',
    }
  }];
}

// ——— Template (from Airtable, fallback to hardcoded Standard) ———
const templateItems = $('Find Template').all().map(i => i.json);
let template;
if (templateItems.length > 0 && templateItems[0].id) {
  const tpl = templateItems[0];
  let segments = tpl.segments_json;
  if (typeof segments === 'string') {
    try { segments = JSON.parse(segments); } catch(e) { segments = null; }
  }
  if (Array.isArray(segments)) {
    template = {
      segments,
      totalDuration: tpl.total_duration_sec || segments.reduce((s, seg) => s + seg.duration, 0),
    };
  }
}
// Fallback: hardcoded Standard template
if (!template) {
  template = {
    segments: [
      { section: 'hook', duration: 3.0 },
      { section: 'screenshot', duration: 1.0 },
      { section: 'upload_chat', duration: 1.0 },
      { section: 'toxic_score', duration: 3.0 },
      { section: 'soul_type', duration: 3.0 },
      { section: 'deep_dive', duration: 3.0 },
    ],
    totalDuration: 14.0,
  };
}

// ——— Music (random pick from active tracks) ———
const musicItems = $('Find Music').all().map(i => i.json);
let musicTrack = null;
if (musicItems.length > 0 && musicItems[0].id) {
  const pick = musicItems[Math.floor(Math.random() * musicItems.length)];
  // Attachment URL from Airtable (valid ~2h), fallback to manual track_url
  const attachUrl = Array.isArray(pick.track_file) && pick.track_file.length > 0
    ? pick.track_file[0].url
    : null;
  musicTrack = {
    trackName: pick.track_name,
    fileUrl: attachUrl || pick.track_url,
    telegramFileId: pick.telegram_file_id,
    bpm: pick.bpm || 120,
    mood: pick.mood,
    durationSec: pick.duration_sec,
  };
}

// ——— Sort and map body clips ———
const bodyClips = clipRecords
  .filter(c => c.clip_type === 'body' || !c.clip_type)
  .sort((a, b) => (a.clip_index || 0) - (b.clip_index || 0))
  .map(clip => ({
    clipIndex: clip.clip_index,
    section: clip.section || 'body_' + clip.clip_index,
    fileId: clip.telegram_file_id,
    duration: clip.clip_duration_sec || 0,
    clipName: clip.clip_name,
  }));

// Map clips to template body segments
const bodySegments = template.segments.filter(s => s.section !== 'hook' && s.section !== 'outro');
const clipMapping = bodySegments.map((seg, i) => {
  let clip = bodyClips.find(c => c.section === seg.section);
  if (!clip && i < bodyClips.length) clip = bodyClips[i];
  return {
    section: seg.section,
    targetDuration: seg.duration,
    fileId: clip ? clip.fileId : null,
    actualDuration: clip ? clip.duration : null,
  };
});

// Hook clip (for manual_clip type)
const hookClips = clipRecords.filter(c => c.clip_type === 'hook_manual');
const hookClipFileId = hookClips.length > 0 ? hookClips[0].telegram_file_id : '';
const hookClipDuration = hookClips.length > 0 ? hookClips[0].clip_duration_sec : 0;

// Outro clip (for manual_clip type)
const outroClips = clipRecords.filter(c => c.clip_type === 'outro_manual');
const outroClipFileId = outroClips.length > 0 ? outroClips[0].telegram_file_id : '';
const outroClipDuration = outroClips.length > 0 ? outroClips[0].clip_duration_sec : 0;

return [{
  json: {
    scenarioName,
    displayName: formatName(scenarioName),
    chatId,
    hookType,
    selectedOutro,
    scenarioJson,
    copyJson,
    template,
    bodyClips,
    clipMapping,
    musicTrack,
    scenarioRecordId: scenario.id,
    hookText: scenario.generated_hook_text || '',
    hookClipFileId,
    hookClipDuration,
    outroClipFileId,
    outroClipDuration,
    girlRefUrl,
    hookPromptTemplate,
    outroPromptTemplate,
    hookEmotionRule,
    girlStylePrompt,
    environmentDescription,
    environmentFurniture,
    hookImageSystemPrompt,
    outroImageSystemPrompt,
    // Sub-concept & Kling fields
    selectedSubconcept,
    effectiveHookType,
    effectiveOutroType,
    hookRefImageUrl,
    outroRefImageUrl,
    hookKlingPrompt,
    outroKlingPrompt,
    hookKlingDuration,
    // Image prompts for kie.ai generation (sub-concept overrides)
    hookImagePrompt: selectedSubconcept ? (selectedSubconcept.hook_image_prompt || '') : '',
    outroImagePrompt: selectedSubconcept ? (selectedSubconcept.outro_image_prompt || '') : '',
    // Outro category from Workflow 1 (organic, app_store, cta_lipsync)
    outroCategory,
    // Time of day for hook/outro image generation lighting
    timeOfDay,
  }
}];

// NODE: Generate Hook (Self-Contained + Env Frame Extraction)
// Routes by hook type from concept config:
//   - manual_clip → pass through the already-uploaded hook clip file_id
//   - ai_image / ai_single_girl → extract env frame from 1st body clip → kie.ai
//   - ai_multi_image → kie.ai x3 images
//   - chat_screenshot → Puppeteer screenshot
//
// Self-contained: downloads first body clip from Telegram, extracts env frame,
// uploads to temp host, then uses [girl_ref, env_frame] as kie.ai references.
// Prompt NEVER describes the girl — only "same exact girl in reference image".
// Mode: Run Once for All Items

// ─── fetch polyfill (n8n Code node sandbox lacks global fetch) ───
const _https = require('https');
const _http = require('http');
const { URL } = require('url');
const fs = require('fs');
const { execSync } = require('child_process');

function fetch(url, opts = {}, _redirectCount = 0) {
  return new Promise((resolve, reject) => {
    if (_redirectCount > 5) return reject(new Error('Too many redirects'));
    const u = new URL(url);
    const lib = u.protocol === 'https:' ? _https : _http;
    const body = opts.body || null;
    const ro = {
      hostname: u.hostname,
      port: u.port || undefined,
      path: u.pathname + u.search,
      method: opts.method || 'GET',
      headers: { ...(opts.headers || {}) },
    };
    if (body) ro.headers['Content-Length'] = Buffer.byteLength(body);
    const req = lib.request(ro, res => {
      // Follow redirects (301, 302, 307, 308)
      if ([301, 302, 307, 308].includes(res.statusCode) && res.headers.location) {
        res.resume(); // drain response
        const redirectUrl = res.headers.location.startsWith('http')
          ? res.headers.location
          : u.protocol + '//' + u.host + res.headers.location;
        return fetch(redirectUrl, opts, _redirectCount + 1).then(resolve).catch(reject);
      }
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const buf = Buffer.concat(chunks);
        resolve({
          ok: res.statusCode >= 200 && res.statusCode < 300,
          status: res.statusCode,
          text: () => Promise.resolve(buf.toString()),
          json: () => Promise.resolve(JSON.parse(buf.toString())),
          arrayBuffer: () => Promise.resolve(buf.buffer.slice(buf.byteOffset, buf.byteOffset + buf.byteLength)),
        });
      });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

// ─── Temp image upload (litterbox.catbox.moe — no API key, 1h expiry) ───
function uploadToTempHost(buffer, filename) {
  return new Promise((resolve, reject) => {
    const boundary = '----FormBoundary' + Date.now();
    const parts = [
      '--' + boundary + '\r\n' +
      'Content-Disposition: form-data; name="reqtype"\r\n\r\n' +
      'fileupload\r\n',
      '--' + boundary + '\r\n' +
      'Content-Disposition: form-data; name="time"\r\n\r\n' +
      '1h\r\n',
      '--' + boundary + '\r\n' +
      'Content-Disposition: form-data; name="fileToUpload"; filename="' + filename + '"\r\n' +
      'Content-Type: image/png\r\n\r\n',
    ];
    const bodyBuf = Buffer.concat([
      Buffer.from(parts.join('')),
      buffer,
      Buffer.from('\r\n--' + boundary + '--\r\n'),
    ]);
    const req = _https.request({
      hostname: 'litterbox.catbox.moe',
      path: '/resources/internals/api.php',
      method: 'POST',
      headers: {
        'Content-Type': 'multipart/form-data; boundary=' + boundary,
        'Content-Length': bodyBuf.length,
      },
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const url = Buffer.concat(chunks).toString().trim();
        if (url.startsWith('https://')) resolve(url);
        else reject(new Error('Upload failed: ' + url));
      });
    });
    req.on('error', reject);
    req.write(bodyBuf);
    req.end();
  });
}

