  await new Promise(r => setTimeout(r, POLL_INTERVAL));
  try {
    const record = await airtableFetch(recordId);
    const status = record.fields?.['hook_approval'];
    if (status === 'approved') {
      return [{ json: { body: { action: 'approve' } } }];
