    if (status === 'redo') {
      try { await airtablePatch(recordId, { 'hook_approval': '' }); } catch(e) {}
      return [{ json: { body: { action: 'redo' } } }];
    }
    // status is 'pending' or empty — keep polling
  } catch (err) {
    // Network error — keep polling
  }
}

