  let pollCount = 0;

  while (Date.now() - pollStart < timeoutMs) {
    await new Promise(r => setTimeout(r, 5000));
    pollCount++;

    try {
      const statusRes = await fetch('https://api.apimart.ai/v1/tasks/' + taskId, {
        headers: { 'Authorization': 'Bearer ' + APIMART_KEY },
      });

      if (!statusRes.ok) {
